// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
  lastUpdated: string; // ISO timestamp of last price update
}

function useComponent(props: Props) {
  const { stocks, lastUpdated } = props;
  return { stocks, lastUpdated };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const { stocks, lastUpdated } = state;
  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-4)">
      <Stack gap="var(--ggui-spacing-4)">
        <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)">
          <Row justify="between" align="center">
            <Heading level={1}>Market Watch</Heading>
            <Text variant="caption">Last Updated: {new Date(lastUpdated).toLocaleTimeString()}</Text>
          </Row>
        </Box>
        <CardGrid columns={{ sm: 1, md: 3 }} gap={16}>
          {stocks.map((stock, i) => {
            const isPositive = (stock.change || 0) >= 0;
            const color = isPositive ? 'var(--ggui-color-success)' : 'var(--ggui-color-error)';
            return (
              <Card key={i} shadow="sm" padding="var(--ggui-spacing-4)" radius="md" border={true}>
                <Stack gap="var(--ggui-spacing-2)">
                  <Heading level={3}>{stock.symbol}</Heading>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{stock.name}</Text>
                  <Heading level={4}>${stock.price?.toFixed(2)}</Heading>
                  <Row align="center" gap="var(--ggui-spacing-1)">
                    <Icon name={isPositive ? 'arrow-up' : 'arrow-down'} size={16} color={color} />
                    <Text color={color} variant="label">
                      {stock.change?.toFixed(2)} ({stock.changePercent?.toFixed(2)}%)
                    </Text>
                  </Row>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}
